import React, { useEffect, useMemo, useState } from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import AdminSidebar from "../components/AdminSidebar";
import StatusBadge from "../components/StatusBadge";
import { getAdminBookings } from "../services/api";
import { formatDateVN, formatTimeVN } from "../utils/format";

function AdminBookings() {
  const [bookings, setBookings] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const data = await getAdminBookings();
        setBookings(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, []);

  const stats = useMemo(() => {
    const total = bookings.length;
    const pending = bookings.filter(
      (b) => String(b.status).toLowerCase() === "pending"
    ).length;
    const confirmed = bookings.filter(
      (b) => String(b.status).toLowerCase() === "confirmed"
    ).length;
    const cancelled = bookings.filter(
      (b) => String(b.status).toLowerCase() === "cancelled"
    ).length;

    return { total, pending, confirmed, cancelled };
  }, [bookings]);

  const filtered = useMemo(() => {
    if (!search.trim()) return bookings;
    const q = search.toLowerCase();
    return bookings.filter(
      (b) =>
        String(b.id).includes(q) ||
        (b.field_name || "").toLowerCase().includes(q) ||
        String(b.user_id).includes(q) ||
        String(b.status).toLowerCase().includes(q)
    );
  }, [bookings, search]);

  return (
    <div>
      <Navbar />

      <div className="container page-section admin-page-layout">
        <AdminSidebar />

        <div className="admin-page-main">
          <div className="match-page-head">
            <div>
              <span className="page-badge">📋 Quản lý booking</span>
              <h1 className="section-title" style={{ marginTop: "10px" }}>Quản lý đặt sân</h1>
              <p className="section-subtitle">
                Theo dõi toàn bộ lượt đặt sân trong hệ thống dưới quyền quản trị viên.
              </p>
            </div>
          </div>

          <div className="admin-stat-grid" style={{ gridTemplateColumns: "repeat(4,1fr)" }}>
            <div className="admin-stat-card admin-stat-blue">
              <div className="admin-stat-icon">📋</div>
              <div className="admin-stat-body">
                <span className="admin-stat-label">Tổng booking</span>
                <strong className="admin-stat-value">{stats.total}</strong>
              </div>
            </div>
            <div className="admin-stat-card admin-stat-orange">
              <div className="admin-stat-icon">⏳</div>
              <div className="admin-stat-body">
                <span className="admin-stat-label">Chờ xác nhận</span>
                <strong className="admin-stat-value">{stats.pending}</strong>
              </div>
            </div>
            <div className="admin-stat-card admin-stat-green">
              <div className="admin-stat-icon">✅</div>
              <div className="admin-stat-body">
                <span className="admin-stat-label">Đã xác nhận</span>
                <strong className="admin-stat-value">{stats.confirmed}</strong>
              </div>
            </div>
            <div className="admin-stat-card" style={{ background: "linear-gradient(135deg,#fef2f2,#fee2e2)", borderColor: "#fecaca", color: "#991b1b" }}>
              <div className="admin-stat-icon" style={{ background: "linear-gradient(135deg,#f87171,#dc2626)" }}>❌</div>
              <div className="admin-stat-body">
                <span className="admin-stat-label">Đã hủy</span>
                <strong className="admin-stat-value">{stats.cancelled}</strong>
              </div>
            </div>
          </div>

          <div className="match-toolbar" style={{ marginBottom: "18px" }}>
            <div className="match-search-box">
              <input
                type="text"
                placeholder="🔍 Tìm theo mã, tên sân, trạng thái..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
          </div>

          {loading && (
            <div className="loading-state">
              <div className="loading-spinner"></div>
              <p>Đang tải dữ liệu booking...</p>
            </div>
          )}
          {error && <p className="error-text">{error}</p>}

          {!loading && !error && filtered.length === 0 && (
            <div className="empty-box">
              {search ? "Không tìm thấy booking phù hợp." : "Hiện chưa có booking nào trong hệ thống."}
            </div>
          )}

          {!loading && !error && filtered.length > 0 && (
            <div className="table-wrap">
              <div className="table-wrap-header">
                <h3>Danh sách booking ({filtered.length})</h3>
              </div>
              <table>
                <thead>
                  <tr>
                    <th>Mã</th>
                    <th>User ID</th>
                    <th>Tên sân</th>
                    <th>Ngày đặt</th>
                    <th>Giờ bắt đầu</th>
                    <th>Giờ kết thúc</th>
                    <th>Trạng thái</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((booking) => (
                    <tr key={booking.id}>
                      <td><strong>#{booking.id}</strong></td>
                      <td>{booking.user_id ?? "—"}</td>
                      <td>{booking.field_name || `Sân #${booking.field_id}`}</td>
                      <td>{formatDateVN(booking.booking_date) || "—"}</td>
                      <td>{formatTimeVN(booking.start_time) || "—"}</td>
                      <td>{formatTimeVN(booking.end_time) || "—"}</td>
                      <td><StatusBadge status={booking.status} /></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default AdminBookings;
